+type cappedBuffer struct {
+	max       int64
+	truncated bool
+	buf       bytes.Buffer
+}
+
+func (b *cappedBuffer) Write(p []byte) (int, error) {
+	if b == nil {
+		return len(p), nil
+	}
+	if b.max <= 0 {
+		if _, err := b.buf.Write(p); err != nil {
+			return 0, err
+		}
+		return len(p), nil
+	}
+
+	remaining := b.max - int64(b.buf.Len())
+	if remaining <= 0 {
+		b.truncated = true
+		return len(p), nil
+	}
+
+	if int64(len(p)) > remaining {
+		if _, err := b.buf.Write(p[:remaining]); err != nil {
+			return 0, err
+		}
+		b.truncated = true
+		return len(p), nil
+	}
+
+	if _, err := b.buf.Write(p); err != nil {
+		return 0, err
+	}
+	return len(p), nil
+}
+
+func (b *cappedBuffer) String() string {
+	if b == nil {
+		return ""
+	}
+	return b.buf.String()
+}
+
+func (b *cappedBuffer) Truncated() bool {
+	if b == nil {
+		return false
+	}
+	return b.truncated
+}
