+	b, err := os.ReadFile(diffPath)
+	if err != nil {
+		t.Fatalf("read diff: %v", err)
+	}
+	if !strings.Contains(string(b), "a.txt") {
+		t.Fatalf("expected diff to mention a.txt")
+	}
+}
